        "pass_condition": "多数通过",
        "thinking": "high"
      },
      {
        "stage": "user_final_decision",
        "role": "用户",
        "description": "用户是最终裁决者，凌霄阁是帮用户把关的"
      }
    ],
    "handler": "architecture-review"
  },
  "enforcement": "runtime_binding",
  "anti_entropy": "此规则本身是对评审流程的固化，防止未来退化为'架构师直出→用户看'的简化流程",
  "enforcement_tier": "P0_gate"
}
