{
  "id": "rule.design-document-structure-001",
  "name": "design_document_structure_standard",
  "domain": "quality",
  "type": "rule",
  "scope": "document",
  "version": "1.0.0",
  "description": "设计文档结构标准——7项强制约束，确保设计文档结构清晰、可读、可维护",
  "rationale": "设计文档结构混乱导致评审效率低、理解成本高，需要统一结构标准",
  "governance": {
    "auto_execute": true,
    "councilRequired": false
  },
  "standard": {
