   309	          const scanner = this._getScanner();
   310	          // 将事件 payload 转为对话切片格式
   311	          const conversationSlice = this._eventToConversationSlice(event);
   312	          const scanResult = await scanner.scan(conversationSlice);
   313	
   314	          if (scanResult && scanResult.intents && scanResult.intents.length > 0) {
   315	            summary.intents_detected += scanResult.intents.length;
   316	
   317	            safeDecisionLog({
   318	              phase: 'execution',
   319	              component: 'l3-pipeline.intent-scanner',
   320	              what: `Detected ${scanResult.intents.length} intents from conversation event`,
   321	              why: `Event: ${event.type} (id=${event.id})`,
   322	              confidence: 1.0,
   323	              input_summary: JSON.stringify({ intents: scanResult.intents.map(i => i.intent || i.name || i.type) }),
   324	            }, flags);
   325	
   326	            // ─── 闭环：意图 emit 回 EventBus ───
   327	            if (flags.eventbus) {
   328	              for (const intent of scanResult.intents) {
   329	                const intentType = `user.intent.${intent.intent || intent.name || intent.type || 'unknown'}.inferred`;
   330	                try {
   331	                  EventBus.emit(intentType, {
   332	                    source_event_id: event.id,
   333	                    source_event_type: event.type,
   334	                    intent_data: intent,
   335	                  }, 'l3-pipeline', {
   336	                    chain_depth: depth + 1,
   337	                    source_pipeline_run: runId,
   338	                  });
   339	                } catch (emitErr) {
   340	                  summary.errors.push({ stage: 'intent-emit', intent: intentType, error: emitErr.message });
   341	                }
   342	              }
   343	            }
   344	          }
   345	        } catch (err) {
   346	          summary.errors.push({ stage: 'intent-scan', event_id: event.id, error: err.message });
   347	        }
   348	      }
   349	
   350	      // ─── Step 2c: Dispatcher 执行匹配到的规则 ───
   351	      if (flags.dispatcher && matchedRules.length > 0) {
   352	        for (const match of matchedRules) {
   353	          try {
   354	            const rule = match.rule;
   355	            const result = await Dispatcher.dispatch(rule, event);
   356	            summary.dispatched_actions++;
   357	
   358	            safeDecisionLog({
   359	              phase: 'execution',
   360	              component: 'l3-pipeline.dispatcher',
   361	              what: `Dispatched action: ${rule.action || rule.id || 'unknown'} → ${result.success ? 'success' : 'failed'}`,
   362	              why: `Rule: ${rule.id || rule.name || 'unnamed'}, Event: ${event.type}`,
   363	              confidence: 1.0,
   364	              input_summary: JSON.stringify({
   365	                rule_id: rule.id || rule.name,
   366	                handler: result.handler,
   367	                success: result.success,
   368	                duration: result.duration,
   369	              }),
   370	            }, flags);
   371	          } catch (err) {
   372	            summary.errors.push({
   373	              stage: 'dispatch',
   374	              rule_id: match.rule.id || match.rule.name,
   375	              event_id: event.id,
   376	              error: err.message,
   377	            });
   378	          }
   379	        }
   380	      }
